import requests
import re
import random
import time
import datetime
import sys
import os
import json
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

# ---------------------- 通用工具函数 ----------------------
def create_retry_session(retries=3, backoff_factor=1, status_forcelist=(500, 502, 503, 504)):
    """创建带重试机制的Session对象"""
    session = requests.Session()
    retry = Retry(
        total=retries,
        read=retries,
        connect=retries,
        backoff_factor=backoff_factor,
        status_forcelist=status_forcelist,
        respect_retry_after_header=True
    )
    adapter = HTTPAdapter(max_retries=retry)
    session.mount('http://', adapter)
    session.mount('https://', adapter)
    return session

def get_time_stamp():
    """获取当前时间戳（毫秒）"""
    return int(time.time() * 1000)

# ---------------------- 核心功能函数 ----------------------
def loginGetCode(user, password):
    """1、登录获取Code（带重试和超时）"""
    is_phone = "@" not in user
    url_user = user if not is_phone else f"+86{user}"
    
    url = f"https://api-user.huami.com/registrations/{url_user}/tokens"
    data = {
        "client_id": "HuaMi",
        "password": password,
        "redirect_uri": "https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html",
        "token": "access"
    }
    headers = {
        "Content-Type": "application/x-www-form-urlencoded;charset=UTF-8",
        "User-Agent": "Mozilla/5.0 (iPhone; CPU iPhone OS 14_7_1 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/14.1.2"
    }

    try:
        session = create_retry_session()
        response = session.post(url, data=data, headers=headers, timeout=(3.05, 10), allow_redirects=False)
        response.raise_for_status()
        
        location = response.headers.get("Location", "")
        if not location:
            raise ValueError("Location header missing in response")
            
        print(f"成功获取Location: {location[:60]}...")  # 截取部分内容避免日志过长
        code = re.search("(?<=access=).*?(?=&)", location)
        return is_phone, code.group(0) if code else None
        
    except (requests.exceptions.RequestException, ValueError) as e:
        print(f"登录获取Code失败: {str(e)}")
        return False, None

def getLoginToken(code, is_phone):
    """2、获取login_token（增强版错误处理）"""
    url = "https://account.huami.com/v2/client/login"
    base_data = {
        "app_name": "com.xiaomi.hm.health",
        "app_version": "6.3.5",
        "code": code,
        "country_code": "CN",
        "device_id": "2C8B4939-0CCD-4E94-8CBA-CB8EA6E613A1",
        "device_model": "phone",
        "grant_type": "access_token",
        "third_name": "huami_phone" if is_phone else "email"
    }
    
    try:
        session = create_retry_session()
        response = session.post(url, data=base_data, timeout=10)
        response.raise_for_status()
        
        result = response.json()
        print("登录响应数据:", json.dumps(result, indent=2, ensure_ascii=False))
        
        if not result.get("token_info"):
            print("登录失败：响应中缺少token_info字段")
            return None, None
            
        token_info = result["token_info"]
        return token_info.get("login_token"), token_info.get("user_id")
        
    except (requests.exceptions.RequestException, json.JSONDecodeError, KeyError) as e:
        print(f"获取login_token失败: {str(e)}")
        return None, None

def getAppToken(login_token):
    """3、获取app_token（完整错误处理）"""
    if not login_token:
        print("无效的login_token")
        return None
        
    url = f"https://account-cn.huami.com/v1/client/app_tokens?app_name=com.xiaomi.hm.health&dn=api-user.huami.com%2Capi-mifit.huami.com%2Capp-analytics.huami.com&login_token={login_token}"
    
    try:
        session = create_retry_session()
        response = session.get(url, timeout=(3.05, 15))
        response.raise_for_status()
        
        data = response.json()
        print("AppToken响应数据:", json.dumps(data, indent=2, ensure_ascii=False))
        
        if not data.get("token_info", {}).get("app_token"):
            print("响应中缺少有效的app_token")
            return None
            
        return data["token_info"]["app_token"]
        
    except (requests.exceptions.RequestException, json.JSONDecodeError, KeyError) as e:
        print(f"获取app_token失败: {str(e)}")
        return None

